import styled from 'styled-components';

export const FullPageImage = styled.div`
  width: 100%;
  height: 100%;
  position: absolute;
  top: 0;
  left: 0;
  background-color: #0B0000;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding-top: 100px;
`;

export const Logo = styled.img`
    margin: 0 auto;
`;

export const Subtext = styled.p`
  color: #ffdcae;
`;
